@app.post("/auth/verify_invite")
async def verify_invite(req: dict):
    code = (req.get("invite_code") or "").strip()
    if not code:
        raise HTTPException(status_code=400, detail="Invite code required.")
    # Check manual codes
    if is_valid_invite_code(code):
        return {"ok": True}
    # Check Lemon Squeezy license key
    try:
        import httpx
        ls_key = os.getenv("LS_API_KEY", "")
        if ls_key:
            r = httpx.post("https://api.lemonsqueezy.com/v1/licenses/validate",
                json={"license_key": code},
                headers={"Authorization": f"Bearer {ls_key}", "Accept": "application/json"},
                timeout=8)
            if r.status_code == 200 and r.json().get("valid"):
                return {"ok": True}
    except Exception:
        pass
    raise HTTPException(status_code=400, detail="Invalid invite code.")

