@app.get("/admin/promotions/audience")
async def audience_data(x_token: Optional[str] = Header(None)):
    verify_admin(x_token)
    if not sb:
        return {"countries":[],"cities":[],"zips":[],"child_counts":[],"child_ages_months":[],"pregnant_count":0,"non_pregnant_count":0,"total_consenting":0}
    try:
        from datetime import date
        result = sb.table("profiles").select("country,city,zip,child_count,children_birthdates,pregnancy_active").eq("consent_marketing", True).execute()
        profiles = result.data or []
        countries = sorted(set(p["country"] for p in profiles if p.get("country")))
        cities = sorted(set(p["city"].strip() for p in profiles if p.get("city") and p["city"].strip()))
        zips = sorted(set(p["zip"].strip() for p in profiles if p.get("zip") and p["zip"].strip()))
        child_counts = sorted(set(p["child_count"] for p in profiles if p.get("child_count") is not None))
        today = date.today()
        all_ages = set()
        for p in profiles:
            for bd in (p.get("children_birthdates") or []):
                try:
                    birth = date.fromisoformat(bd)
                    m = (today.year - birth.year) * 12 + (today.month - birth.month)
                    if today.day < birth.day:
                        m -= 1
                    all_ages.add(max(0, m))
                except Exception:
                    pass
        pregnant_count = sum(1 for p in profiles if p.get("pregnancy_active"))
        return {
            "countries": countries,
            "cities": cities,
            "zips": zips,
            "child_counts": child_counts,
            "child_ages_months": sorted(all_ages),
            "pregnant_count": pregnant_count,
            "non_pregnant_count": len(profiles) - pregnant_count,
            "total_consenting": len(profiles),
        }
    except Exception as e:
        return {"countries":[],"cities":[],"zips":[],"child_counts":[],"child_ages_months":[],"error":str(e)}

@app.get("/admin/users")
async def admin_list_users(x_token: Optional[str] = Header(None)):
    verify_admin(x_token)
    if not sb:
        return {"users": []}
    try:
        columns = "id,email,name,plan,subscription_status,trial_ends_at,created_at,last_login,role,must_change_password"
        app_users = _paginate_table_rows("users", columns)
        for row in app_users:
            row["account_kind"] = "registered"

        known_ids = {u.get("id") for u in app_users if u.get("id")}
        auth_only: list = []
        for auth_user in _list_all_auth_users():
            row = _auth_user_row(auth_user)
            if row.get("id") and row["id"] not in known_ids:
                auth_only.append(row)

        invite_only_count = 0
        try:
            invite_res = (
                sb.table("profiles")
                .select("token", count="exact")
                .is_("user_id", "null")
                .not_.is_("token", "null")
                .limit(1)
                .execute()
            )
            invite_only_count = invite_res.count or 0
        except Exception:
            pass

        merged = app_users + auth_only
        merged.sort(key=lambda u: u.get("created_at") or "", reverse=True)
        return {
            "users": merged,
            "registered_count": len(app_users),
            "auth_only_count": len(auth_only),
            "invite_only_count": invite_only_count,
        }
    except Exception as e:
        return {"users": [], "error": str(e)}

