def _auth_user_id(resp) -> Optional[str]:
    user = getattr(resp, "user", None)
    if user is None and isinstance(resp, dict):
        user = resp.get("user")
    if user is None:
        return None
    if hasattr(user, "id"):
        return user.id
    if isinstance(user, dict):
        return user.get("id")
    return None

def _user_insert_error_detail(exc: Exception) -> str:
    detail = str(exc)
    low = detail.lower()
    if "password_hash" in low:
        return (
            "Could not save user row: password_hash column still required. "
            "Run backend/migrations/users_drop_password_hash.sql in Supabase SQL Editor."
        )
    if "users_id_fkey" in low or "foreign key" in low:
        return f"Could not save user row (auth/users link): {detail}"
    return f"Could not save user row: {detail}"


def _tester_plan_fields(plan: str) -> dict:
    if plan == "premium":
        return {"plan": "premium", "subscription_status": "active"}
    return {"plan": "starter", "subscription_status": "active"}


def supabase_create_auth_user(email: str, user_metadata: dict, password: Optional[str] = None) -> str:
    """Create auth.users via admin API — no Supabase invite/confirmation email."""
    import secrets

    user_id = str(uuid.uuid4())
    auth_password = password.strip() if password and password.strip() else secrets.token_urlsafe(32)
    try:
        sb.auth.admin.create_user({
            "id": user_id,
            "email": email,
            "password": auth_password,
            "email_confirm": True,
            "user_metadata": user_metadata,
        })
    except Exception as e:
        err = str(e).lower()
        detail = str(e)
        if "bearer token" in detail.lower():
            detail = (
                "Supabase auth misconfigured: SUPABASE_SERVICE_KEY must be the service_role "
                "secret from Supabase Dashboard → Settings → API (not the anon key)."
            )
        if "already" in err or "registered" in err or "exists" in err:
            raise HTTPException(status_code=400, detail="Email already registered.")
        raise HTTPException(status_code=500, detail=detail)
    return user_id


