# Lemon Squeezy Webhook
@app.post("/webhooks/lemon")
async def lemon_webhook(request: Request):
    try:
        import secrets as _secrets
        from datetime import datetime as _dt
        payload = await request.json()
        attrs = payload.get("data", {}).get("attributes", {})
        customer_email = attrs.get("user_email") or attrs.get("customer_email") or ""
        product_name = attrs.get("product_name", "HeyMaa")
        plan = "starter"
        if "199" in product_name.lower() or "annual" in product_name.lower():
            plan = "annual_premium"
        elif "39" in product_name.lower() or "premium" in product_name.lower():
            plan = "premium"
        invite_code = "LS-" + _secrets.token_urlsafe(12)
        created_at = _dt.utcnow().isoformat()
        if sb and customer_email:
            try:
                sb.table("pending_invites").upsert({
                    "email": customer_email.lower().strip(),
                    "invite_code": invite_code,
                    "plan": plan,
                    "created_at": created_at,
                    "used": False,
                }).execute()
            except Exception:
                pass
            try:
                import resend as _resend
                _resend.api_key = RESEND_API_KEY
                app_link = f"{APP_URL}?invite={invite_code}"
                html_body = (
                    "<div style='font-family:sans-serif;max-width:520px;margin:auto;padding:24px'>"
                    "<h2 style='color:#2B3A67'>Kalws irthes sto HeyMaa!</h2>"
                    f"<p>I syndromh sou ({plan}) energopoihthike.</p>"
                    f"<p><a href='{app_link}' style='background:#2B3A67;color:#fff;padding:12px 24px;border-radius:8px;text-decoration:none;display:inline-block'>Xekinise to HeyMaa</a></p>"
                    f"<p style='font-size:12px;color:#888'>Kwdikos: {invite_code}</p>"
                    "</div>"
                )
                _resend.Emails.send({
                    "from": RESEND_FROM,
                    "to": customer_email,
                    "subject": "Kalws irthes sto HeyMaa!",
                    "html": html_body
                })
            except Exception:
                pass
        return {"ok": True}
    except Exception as e:
        return {"ok": False, "error": str(e)}



# == User Data Persistence ==
@app.get("/userdata")
async def get_userdata(key: str = None, x_token: str = Header(None)):
    auth = resolve_auth(x_token)
    if not sb:
        raise HTTPException(status_code=503, detail="DB unavailable")
    try:
        if auth["kind"] == "invite":
            q = sb.table("user_data").select("key,value").eq("token", auth["token"])
        else:
            q = sb.table("user_data").select("key,value").eq("user_id", auth["user_id"])
        if key:
            q = q.eq("key", key)
        res = q.execute()
        if key:
            row = next((r for r in (res.data or []) if r["key"] == key), None)
            return {"value": row["value"] if row else None}
        return {"data": {r["key"]: r["value"] for r in (res.data or [])}}
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))

@app.post("/userdata")
async def set_userdata(body: dict, x_token: str = Header(None)):
    auth = resolve_auth(x_token)
    if not sb:
        raise HTTPException(status_code=503, detail="DB unavailable")
    key = body.get("key")
    value = body.get("value")
    if not key:
        raise HTTPException(status_code=400, detail="key required")
    try:
        import datetime as _dt
        updated_at = _dt.datetime.utcnow().isoformat()
        user_data_upsert(auth, key, value, updated_at)
        return {"ok": True}
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))

